-- 1. Drop existing tables if re-creating
DROP TABLE IF EXISTS scores;
DROP TABLE IF EXISTS mocks;

-- 2. Create Schema
CREATE TABLE mocks (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  name TEXT UNIQUE NOT NULL,
  parts JSONB NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE scores (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  mock_name TEXT NOT NULL,
  candidate_name TEXT NOT NULL,
  scores JSONB NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  CONSTRAINT unique_mock_candidate UNIQUE(mock_name, candidate_name)
);

-- 3. Enable RLS and Policies
ALTER TABLE mocks ENABLE ROW LEVEL SECURITY;
ALTER TABLE scores ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public read/write mocks" ON mocks FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow public read/write scores" ON scores FOR ALL USING (true) WITH CHECK (true);

